/* adm-system-userhistory-sql-oracle.xml - selectUserHistory */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT A.URLILOHKEY AS URLILOHKEY ,A.IPADDR AS IPADDRESS ,A.SESSIONID AS SESSIONID ,A.URKEY AS URKEY ,B.URNM ,A.LOGINDATE AS LOGINDATE ,A.LOGOUTDATE AS LOGOUTDATE ,A.INSERTDATE AS INSERTDATE FROM TADMIN_INFO_URLILOH A INNER JOIN TADMIN_MST_UR B ON A.URKEY = B.URKEY WHERE 1 = 1
AND #{SEARCH_CONDITION}
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY URLILOHKEY DESC
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

mapper.update:
/* adm-system-userhistory-sql-oracle.xml - updateTAdminInfoUrliloh */
UPDATE TADMIN_INFO_URLILOH
   SET LOGOUTDATE  = #{logoutdate}
 WHERE 
 	  URLILOHKEY = #{urlilohkey}

