INSERT INTO TADMIN_INFO_URLILOH (
	  	URLILOHKEY
	  , IPADDR
	  , SESSIONID
	  , URKEY
	  , LOGINDATE
	  , INSERTDATE
) VALUES (
	   #{urlilohkey}
	 , #{ipaddr}
	 , #{sessionId}
	 , #{urkey}
	 , #{sysdate}
	 , #{sysdate}
 )

